export type ApiResponse<T> = { ok: true; data: T; meta: ApiResponseMetadata; auditId?: string; eventId?: string } | { ok: false; error: ApiError; meta: ApiResponseMetadata; auditId?: string; eventId?: string };
export type ContractFieldType = 'string'|'number'|'boolean'|'array'|'object';
export interface ContractRule { path: string; required?: boolean; type?: ContractFieldType; values?: readonly (string | number | boolean)[]; min?: number; max?: number }
export interface EndpointContract { method: 'GET'|'POST'|'PATCH'|'DELETE'; path: string; operationId: string; response: string; roles: NexusRole[]|'authenticated'; requiredPermission: Permission; emits: string[]; audits: string[]; description: string; request?: string; responseEnvelope: 'ApiResponse'; pagination?: 'none'|'offset'|'cursor'; metadata: readonly ('requestId'|'timestamp'|'tenantId'|'racetrackId'|'organizationId'|'actorId'|'role'|'pagination')[] }
export const nexusApiBasePath = '/api/v1';

const isRecord = (value: unknown): value is Record<string, unknown> => typeof value === 'object' && value !== null;
const get = (obj: unknown, path: string): unknown => path.split('.').reduce<unknown>((acc, key) => (isRecord(acc) ? acc[key] : undefined), obj);
export function validateContract(name: string, value: unknown, rules: readonly ContractRule[]): { valid: boolean; errors: string[] } {
  const errors: string[] = [];
  for (const rule of rules) {
    const v = get(value, rule.path);
    if (rule.required && (v === undefined || v === null || v === '')) errors.push(`${name}.${rule.path} is required`);
    if (v !== undefined && rule.type) {
      const ok = rule.type === 'array' ? Array.isArray(v) : typeof v === rule.type;
      if (!ok) errors.push(`${name}.${rule.path} must be ${rule.type}`);
    }
    if (rule.values && v !== undefined && !rule.values.some((allowed) => allowed === v || String(allowed) === String(v))) errors.push(`${name}.${rule.path} must be one of ${rule.values.join(',')}`);
    if (typeof v === 'number' && rule.min !== undefined && v < rule.min) errors.push(`${name}.${rule.path} must be >= ${rule.min}`);
    if (typeof v === 'number' && rule.max !== undefined && v > rule.max) errors.push(`${name}.${rule.path} must be <= ${rule.max}`);
  }
  return { valid: errors.length === 0, errors };
}
export function assertContract<T>(name: string, value: T, rules: readonly ContractRule[]): T { const result = validateContract(name, value, rules); if (!result.valid) throw new Error(result.errors.join('; ')); return value; }

