export const apiEndpointContracts: EndpointContract[] = apiEndpointContractDefinitions.map((endpoint) => {
  const paginated = endpoint.method === 'GET' && endpoint.response.endsWith('[]');
  const metadata: EndpointContract['metadata'] = paginated ? ['requestId','timestamp','tenantId','racetrackId','organizationId','role','pagination'] : ['requestId','timestamp','tenantId','racetrackId','organizationId','role'];
  return {
    method: endpoint.method,
    path: endpoint.path,
    operationId: endpoint.operationId,
    response: endpoint.response,
    roles: endpoint.roles === 'authenticated' ? endpoint.roles : [...endpoint.roles],
    requiredPermission: permissionForApiEndpoint(endpoint),
    emits: [...endpoint.emits],
    audits: [...endpoint.audits],
    description: endpoint.description,
    responseEnvelope: 'ApiResponse' as const,
    pagination: paginated ? 'offset' : 'none',
    metadata,
  };
});
